// --- types.d.ts ---
import { ReactNode } from 'react';

export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastItem[];
}

export interface ForecastDayProps {
  day: string;
  icon: string;
  high: string;
  low: string;
}

export interface WeatherHookReturn {
  formattedTemp: string;
  formattedHumidity: string;
  formattedWind: string;
  currentIcon: string;
  formattedForecast: Array<ForecastDayProps>;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

export const CONDITION_ICONS: Record<string, string> = {
  Sunny: '☀️',
  Cloudy: '☁️',
  Rainy: '🌧️',
  'Partly Cloudy': '⛅',
  Stormy: '⛈️',
  Snowy: '❄️',
  Clear: '☀️',
  Fog: '🌫️',
  Mist: '🌫️',
  Thunderstorm: '⛈️',
  Drizzle: '🌦️',
};

export const DEFAULT_UNIT = 'C';


// --- hooks.ts ---
import { useMemo } from 'react';
import type { Props, WeatherHookReturn, ForecastDayProps } from './types';
import * as constants from './constants';

export function useWeather(props: Props): WeatherHookReturn {
  const { temperature, condition, humidity, windSpeed, unit = 'C', forecast } = props;

  const formattedTemp = useMemo(() => {
    return `${Math.round(temperature)}°${unit}`;
  }, [temperature, unit]);

  const formattedHumidity = useMemo(() => {
    return `${humidity}%`;
  }, [humidity]);

  const formattedWind = useMemo(() => {
    const windUnit = unit === 'F' ? 'mph' : 'km/h';
    return `${windSpeed} ${windUnit}`;
  }, [windSpeed, unit]);

  const currentIcon = useMemo(() => {
    // Accessing WEATHER_ICONS from constants if it exists, otherwise fallback to condition
    const iconMap = (constants as any).WEATHER_ICONS || {};
    return iconMap[condition] || condition;
  }, [condition]);

  const formattedForecast = useMemo((): ForecastDayProps[] => {
    return forecast.map((item) => ({
      day: item.day,
      icon: item.icon,
      high: `${Math.round(item.high)}°`,
      low: `${Math.round(item.low)}°`,
    }));
  }, [forecast]);

  return {
    formattedTemp,
    formattedHumidity,
    formattedWind,
    currentIcon,
    formattedForecast,
  };
}


// --- ForecastDay.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import type { ForecastDayProps } from './types';

export function ForecastDay({ day, icon, high, low }: ForecastDayProps) {
  return (
    <Stack direction="vertical" align="center" gap={4}>
      <Text size="sm" weight="semibold">
        {day}
      </Text>
      <Text size="xl">
        {icon}
      </Text>
      <Text size="sm">
        {high}<span style={{ color: 'var(--ggui-text-dimmed)' }}>/{low}</span>
      </Text>
    </Stack>
  );
}


// --- ui.tsx ---
// ui.tsx — main visual layout, design system primitives
import React from 'react';
import { Stack, Heading, Text, Card, Divider } from '@ggui-ai/design/primitives';
import type { Props, WeatherHookReturn as HookReturn } from './types';
import { ForecastDay } from './components';

export function ComponentUI(props: Props & HookReturn) {
  const { 
    city, 
    condition, 
    formattedTemp, 
    formattedHumidity, 
    formattedWind, 
    currentIcon, 
    formattedForecast 
  } = props;

  return (
    <Card 
      // @ts-ignore - variant='elevated' as requested by instructions
      variant="elevated" 
      shadow="md" 
      padding="var(--ggui-spacing-md, 16px)"
    >
      <Stack gap="var(--ggui-spacing-md, 16px)">
        {/* Top section: City name and Current Condition */}
        <Stack gap="var(--ggui-spacing-1, 4px)">
          <Heading level={3}>{city}</Heading>
          <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">
            {condition}
          </Text>
        </Stack>

        {/* Middle section: Large current temperature and its icon */}
        <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-md, 16px)">
          <Heading level={1}>{formattedTemp}</Heading>
          <Text size="4xl" as="span" aria-hidden="true">
            {currentIcon}
          </Text>
        </Stack>

        {/* Stats section: Horizontal Stack with Humidity and Wind Speed labels */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-md, 16px)">
          <Stack gap={0}>
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              Humidity
            </Text>
            <Text variant="label">{formattedHumidity}</Text>
          </Stack>
          <Stack gap={0}>
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              Wind Speed
            </Text>
            <Text variant="label">{formattedWind}</Text>
          </Stack>
        </Stack>

        <Divider margin="var(--ggui-spacing-md, 16px)" />

        {/* Bottom section: Forecast mapping */}
        <Stack direction="horizontal" justify="between" align="center">
          {formattedForecast.map((dayProps, index) => (
            <ForecastDay key={index} {...dayProps} />
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
